import React, { useState, useEffect, useRef, useCallback } from 'react';
import api from '../services/api';

const STATUS_COLOR = {
  PENDING:   { bg: 'rgba(201,168,76,0.15)',  color: '#C9A84C', border: 'rgba(201,168,76,0.35)' },
  MATCHED:   { bg: 'rgba(76,175,130,0.15)',  color: '#4CAF82', border: 'rgba(76,175,130,0.35)' },
  ACTIVE:    { bg: 'rgba(91,147,232,0.15)',  color: '#5B93E8', border: 'rgba(91,147,232,0.35)' },
  COMPLETED: { bg: 'rgba(120,120,120,0.1)',  color: '#888',    border: 'rgba(120,120,120,0.2)' },
  CANCELLED: { bg: 'rgba(232,85,85,0.12)',   color: '#E85555', border: 'rgba(232,85,85,0.25)' },
};

function StatusBadge({ status }) {
  const s = STATUS_COLOR[status] || STATUS_COLOR.PENDING;
  return (
    <span style={{ padding: '3px 10px', borderRadius: 99, fontSize: 11, fontWeight: 700, letterSpacing: '0.04em',
      background: s.bg, color: s.color, border: `1px solid ${s.border}` }}>
      {status}
    </span>
  );
}

function CountdownTimer({ seconds, onExpire }) {
  const [remaining, setRemaining] = useState(seconds);
  useEffect(() => {
    if (remaining <= 0) { onExpire?.(); return; }
    const t = setTimeout(() => setRemaining(r => r - 1), 1000);
    return () => clearTimeout(t);
  }, [remaining]);
  const pct = (remaining / seconds) * 100;
  const color = remaining > 10 ? '#4CAF82' : remaining > 5 ? '#C9A84C' : '#E85555';
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
      <div style={{ flex: 1, height: 4, borderRadius: 2, background: 'var(--bg-4)', overflow: 'hidden' }}>
        <div style={{ height: '100%', width: `${pct}%`, background: color, transition: 'width 1s linear, background 0.3s' }} />
      </div>
      <span style={{ fontSize: 12, fontWeight: 700, color, minWidth: 24, textAlign: 'right' }}>{remaining}s</span>
    </div>
  );
}

export default function DriverNotificationPanel() {
  const user      = JSON.parse(localStorage.getItem('zipride_user') || '{}');
  const driverId  = user.driverId || user.id || 1;

  const [rides,      setRides]      = useState([]);
  const [myRides,    setMyRides]    = useState([]);
  const [loading,    setLoading]    = useState(false);
  const [accepting,  setAccepting]  = useState(null);  // rideId being accepted
  const [lastFetch,  setLastFetch]  = useState(null);
  const [autoRefresh,setAutoRefresh]= useState(true);
  const [flash,      setFlash]      = useState([]);    // newly appeared ride ids
  const prevRideIds  = useRef(new Set());
  const pollRef      = useRef(null);

  const fetchRides = useCallback(async () => {
    setLoading(true);
    try {
      const { data } = await api.get('/api/fare/rides');
      const allRides  = Array.isArray(data) ? data : [];
      const pending   = allRides.filter(r => r.status === 'PENDING');
      const mine      = allRides.filter(r => r.driverId === driverId && ['MATCHED','ACTIVE'].includes(r.status));

      // Detect newly appeared rides for flash animation
      const newIds = pending.map(r => r.id).filter(id => !prevRideIds.current.has(id));
      if (newIds.length > 0) setFlash(newIds);
      prevRideIds.current = new Set(pending.map(r => r.id));

      setRides(pending);
      setMyRides(mine);
      setLastFetch(new Date());
    } catch {
      // Generate demo data if backend unavailable
      const demo = [
        { id: 1001, passengerId: 3, pickupLat: 11.9344, pickupLng: 79.8361, dropLat: 12.0059, dropLng: 79.8105, vehicleType: 'SEDAN', zone: 'ZONE_A', status: 'PENDING', estimatedFare: 145.50, requestTime: new Date().toISOString() },
        { id: 1002, passengerId: 7, pickupLat: 11.9330, pickupLng: 79.8370, dropLat: 11.9801, dropLng: 79.8126, vehicleType: 'AUTO',  zone: 'ZONE_B', status: 'PENDING', estimatedFare: 62.00,  requestTime: new Date().toISOString() },
      ];
      setRides(demo);
      setLastFetch(new Date());
    }
    setLoading(false);
  }, [driverId]);

  // Auto-poll every 8 seconds
  useEffect(() => {
    fetchRides();
    if (autoRefresh) {
      pollRef.current = setInterval(fetchRides, 8000);
    }
    return () => clearInterval(pollRef.current);
  }, [autoRefresh, fetchRides]);

  // Clear flash after animation
  useEffect(() => {
    if (flash.length > 0) {
      const t = setTimeout(() => setFlash([]), 2000);
      return () => clearTimeout(t);
    }
  }, [flash]);

  const acceptRide = async (ride) => {
    setAccepting(ride.id);
    try {
      // Try the accept endpoint first
      await api.patch(`/api/fare/rides/${ride.id}/accept`, null, { params: { driverId } });
    } catch {
      // Fallback: update via PUT with new status + driverId
      try {
        await api.post('/api/fare/rides', { ...ride, driverId, status: 'MATCHED' });
      } catch {}
    }
    // Optimistically update UI
    setRides(prev => prev.filter(r => r.id !== ride.id));
    setMyRides(prev => [...prev, { ...ride, driverId, status: 'MATCHED' }]);
    setAccepting(null);
  };

  const declineRide = (rideId) => {
    setRides(prev => prev.filter(r => r.id !== rideId));
  };

  const toggleAutoRefresh = () => {
    setAutoRefresh(p => {
      if (!p) fetchRides();
      else clearInterval(pollRef.current);
      return !p;
    });
  };

  return (
    <>
      {/* ── Header controls ── */}
      <div className="panel" style={{ marginBottom: 0 }}>
        <div className="panel-header">
          <h3>📡 Ride Notifications</h3>
          <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
            {loading && <span className="spinner" style={{ width: 14, height: 14 }} />}
            {lastFetch && (
              <span style={{ fontSize: 11, color: 'var(--text-muted)' }}>
                Updated {lastFetch.toLocaleTimeString()}
              </span>
            )}
            <button className={`btn-secondary ${autoRefresh ? 'active' : ''}`}
              onClick={toggleAutoRefresh}
              style={{ padding: '5px 12px', fontSize: 12, background: autoRefresh ? 'rgba(76,175,130,0.15)' : undefined, color: autoRefresh ? 'var(--green)' : undefined, border: autoRefresh ? '1px solid rgba(76,175,130,0.4)' : undefined }}>
              {autoRefresh ? '🟢 Live' : '⚫ Paused'}
            </button>
            <button className="btn-secondary" onClick={fetchRides} style={{ padding: '5px 12px', fontSize: 12 }}>
              ↻ Refresh
            </button>
          </div>
        </div>
      </div>

      {/* ── Pending ride requests ── */}
      <div className="panel">
        <div className="panel-header">
          <h3>🔔 Incoming Requests</h3>
          <span className="badge">{rides.length} pending</span>
        </div>
        <div className="panel-body">
          {rides.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '32px 0', color: 'var(--text-muted)' }}>
              <div style={{ fontSize: 40, marginBottom: 12 }}>🚖</div>
              <div style={{ fontSize: 14 }}>No pending ride requests.</div>
              <div style={{ fontSize: 12, marginTop: 6 }}>Auto-refreshing every 8 seconds…</div>
            </div>
          ) : (
            <div style={{ display: 'grid', gap: 16 }}>
              {rides.map(ride => {
                const isFlash    = flash.includes(ride.id);
                const isAccepting = accepting === ride.id;
                const distKm = Math.sqrt(
                  Math.pow((ride.dropLat - ride.pickupLat) * 111, 2) +
                  Math.pow((ride.dropLng - ride.pickupLng) * 111 * Math.cos(ride.pickupLat * Math.PI / 180), 2)
                ).toFixed(1);

                return (
                  <div key={ride.id} style={{
                    borderRadius: 14,
                    border: isFlash ? '2px solid var(--gold)' : '1px solid var(--border)',
                    background: isFlash ? 'rgba(201,168,76,0.06)' : 'var(--bg-3)',
                    padding: '18px 20px',
                    transition: 'all 0.4s',
                    boxShadow: isFlash ? '0 0 20px rgba(201,168,76,0.2)' : 'none',
                  }}>
                    {/* Top row */}
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 14 }}>
                      <div>
                        {isFlash && (
                          <div style={{ fontSize: 11, fontWeight: 700, color: 'var(--gold)', marginBottom: 4, letterSpacing: '0.06em' }}>
                            ✨ NEW REQUEST
                          </div>
                        )}
                        <div style={{ fontFamily: 'Playfair Display', fontSize: 17, fontWeight: 700 }}>
                          Ride #{ride.id}
                        </div>
                        <div style={{ fontSize: 12, color: 'var(--text-muted)', marginTop: 2 }}>
                          Passenger ID: {ride.passengerId} · {new Date(ride.requestTime).toLocaleTimeString()}
                        </div>
                      </div>
                      <StatusBadge status={ride.status} />
                    </div>

                    {/* Route */}
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10, marginBottom: 14 }}>
                      <div style={{ padding: '10px 12px', background: 'rgba(76,175,130,0.1)', borderRadius: 10, border: '1px solid rgba(76,175,130,0.2)' }}>
                        <div style={{ fontSize: 10, color: 'var(--green)', fontWeight: 700, marginBottom: 4 }}>📍 PICKUP</div>
                        <div style={{ fontSize: 12, fontWeight: 600, color: 'var(--text-pri)' }}>
                          {ride.pickupLat?.toFixed(4)}, {ride.pickupLng?.toFixed(4)}
                        </div>
                      </div>
                      <div style={{ padding: '10px 12px', background: 'rgba(232,85,85,0.1)', borderRadius: 10, border: '1px solid rgba(232,85,85,0.2)' }}>
                        <div style={{ fontSize: 10, color: '#E85555', fontWeight: 700, marginBottom: 4 }}>🏁 DROP</div>
                        <div style={{ fontSize: 12, fontWeight: 600, color: 'var(--text-pri)' }}>
                          {ride.dropLat?.toFixed(4)}, {ride.dropLng?.toFixed(4)}
                        </div>
                      </div>
                    </div>

                    {/* Ride details */}
                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 8, marginBottom: 14 }}>
                      {[
                        ['🚗 Vehicle', ride.vehicleType],
                        ['📏 Distance', `~${distKm} km`],
                        ['💰 Fare',    `₹${ride.estimatedFare?.toFixed(2) || '—'}`],
                      ].map(([k, v]) => (
                        <div key={k} style={{ padding: '8px 10px', background: 'var(--bg-4)', borderRadius: 8, textAlign: 'center' }}>
                          <div style={{ fontSize: 10, color: 'var(--text-muted)', marginBottom: 3 }}>{k}</div>
                          <div style={{ fontSize: 13, fontWeight: 700, color: 'var(--text-pri)' }}>{v}</div>
                        </div>
                      ))}
                    </div>

                    {/* Countdown */}
                    <div style={{ marginBottom: 14 }}>
                      <div style={{ fontSize: 10, color: 'var(--text-muted)', fontWeight: 600, marginBottom: 5 }}>
                        ⏳ OFFER WINDOW
                      </div>
                      <CountdownTimer seconds={30} onExpire={() => declineRide(ride.id)} />
                    </div>

                    {/* Action buttons */}
                    <div style={{ display: 'flex', gap: 10 }}>
                      <button onClick={() => declineRide(ride.id)}
                        style={{ flex: 0.4, padding: '11px 0', borderRadius: 10, border: '1px solid var(--border)', background: 'none', color: 'var(--text-secondary)', fontSize: 13, fontWeight: 600, cursor: 'pointer', transition: 'all .18s' }}
                        onMouseEnter={e => { e.target.style.background = 'rgba(232,85,85,0.1)'; e.target.style.color = '#E85555'; e.target.style.borderColor = 'rgba(232,85,85,0.4)'; }}
                        onMouseLeave={e => { e.target.style.background = 'none'; e.target.style.color = 'var(--text-secondary)'; e.target.style.borderColor = 'var(--border)'; }}>
                        ✕ Decline
                      </button>
                      <button className="btn-action" style={{ flex: 1, padding: '11px 0' }}
                        onClick={() => acceptRide(ride)} disabled={isAccepting}>
                        {isAccepting ? <><span className="spinner" /> Accepting…</> : '✓ Accept Ride'}
                      </button>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>

      {/* ── Active / matched rides ── */}
      {myRides.length > 0 && (
        <div className="panel">
          <div className="panel-header">
            <h3>🚀 My Active Rides</h3>
            <span className="badge">{myRides.length}</span>
          </div>
          <div className="panel-body">
            <div style={{ display: 'grid', gap: 12 }}>
              {myRides.map(ride => (
                <div key={ride.id} style={{ padding: '14px 16px', background: 'var(--bg-3)', borderRadius: 12, border: '1px solid var(--border)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <div>
                    <div style={{ fontWeight: 700, fontSize: 14 }}>Ride #{ride.id}</div>
                    <div style={{ fontSize: 12, color: 'var(--text-muted)', marginTop: 2 }}>
                      Passenger {ride.passengerId} · {ride.vehicleType} · ₹{ride.estimatedFare?.toFixed(2)}
                    </div>
                  </div>
                  <StatusBadge status={ride.status} />
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </>
  );
}
